{
  "days": [
    {
      "day": 1,
      "theme": "大同古建筑与石窟艺术",
      "pois": [
        {
          "name": "云冈石窟",
          "lat": 40.11,
          "lng": 113.13,
          "stay_time": 180,
          "description": "中国四大石窟之一，北魏时期皇家开凿的佛教艺术宝库，现存主要洞窟45个，造像51000余尊，代表了公元5世纪至6世纪中国石窟艺术的最高成就。"
        },
        {
          "name": "华严寺",
          "lat": 40.09,
          "lng": 113.29,
          "stay_time": 120,
          "description": "辽金时期皇家寺院，中国现存年代较早、保存较完整的一座辽金寺庙建筑群，分为上华严寺和下华严寺，以薄伽教藏殿内的辽代彩塑闻名。"
        },
        {
          "name": "善化寺",
          "lat": 40.08,
          "lng": 113.29,
          "stay_time": 90,
          "description": "全国重点文物保护单位，始建于唐代，现存主要建筑为辽金遗构，是中国现存规模最大、最为完整的辽金时期建筑群之一。"
        }
      ],
      "distance": 300,
      "drive_time": 210
    },
    {
      "day": 2,
      "theme": "应县木塔与悬空寺奇观",
      "pois": [
        {
          "name": "应县木塔",
          "lat": 39.56,
          "lng": 113.18,
          "stay_time": 120,
          "description": "世界现存最高最古的纯木结构楼阁式建筑，建于辽清宁二年（1056年），高67.31米，与意大利比萨斜塔、巴黎埃菲尔铁塔并称世界三大奇塔。"
        },
        {
          "name": "悬空寺",
          "lat": 39.66,
          "lng": 113.70,
          "stay_time": 120,
          "description": "北岳恒山十八景中第一胜景，建于北魏后期，是中国仅存的佛、道、儒三教合一的独特寺庙，悬挂在恒山金龙峡西侧翠屏峰的峭壁间。"
        }
      ],
      "distance": 340,
      "drive_time": 300
    }
  ]
}
